const input = $input.first().json.body || $input.first().json;

// VRF — GUARD + VALIDATE
const isValidUUID = (v) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v);
const bookingId = input.old_booking_id || input.booking_id;

if (!bookingId || !isValidUUID(bookingId)) {
  throw new Error('Invalid or missing booking_id (UUID required)');
}
if (!input.new_start_time) {
  throw new Error('Missing required field: new_start_time');
}

return [{
  json: {
    chat_id: parseInt(input.chat_id) || null,
    booking_id: bookingId,
    old_booking_id: bookingId,
    new_start_time: input.new_start_time,
    provider_id: parseInt(input.provider_id) || 1,
    service_id: parseInt(input.service_id) || 1,
    user_email: input.user_email || '',
    user_name: input.user_name || 'Paciente'
  }
}];

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      old_booking_id: $node["Build Secure JSON"]?.json?.old_booking_id || $node["Build Secure JSON"]?.json?.booking_id,
      new_booking_id: $node["Step 2: Create New"]?.json?.data?.booking_id || $node["Step 2: Create New"]?.json?.booking_id || null
    },
    _meta: { source: "DB_Reschedule_Booking", timestamp: new Date().toISOString() }
  }
}];
